async acquire(cost = 1): Promise<void> {
  if (cost <= 0) return;
  if (cost > this.capacity) {
    throw new Error(...);
  }
  if (this.tokens >= cost) {
    this.tokens -= cost;
    return;
  }
  return new Promise<void>((resolve) => {
    this.waiters.push({ needed: cost, resolve });
  });
}

